## Implementation

### Message Writer
```rust
pub struct MessageWriter {
    buf: Vec<u8>,
}

impl MessageWriter {
    pub fn new() -> Self;

    /// Write a frontend message
    pub fn write(&mut self, msg: &FrontendMessage) -> &[u8] {
        self.buf.clear();

        match msg {
            FrontendMessage::Startup { version, params } => {
                // No type byte for startup
                let mut body = Vec::new();
                body.extend_from_slice(&version.to_be_bytes());
                for (key, value) in params {
                    body.extend_from_slice(key.as_bytes());
                    body.push(0);
                    body.extend_from_slice(value.as_bytes());
                    body.push(0);
                }
                body.push(0);  // Terminator

                let len = (body.len() + 4) as i32;
                self.buf.extend_from_slice(&len.to_be_bytes());
                self.buf.extend(body);
            }
            FrontendMessage::Query(sql) => {
                self.buf.push(b'Q');
                let len = (sql.len() + 5) as i32;  // 4 for length + 1 for null
                self.buf.extend_from_slice(&len.to_be_bytes());
                self.buf.extend_from_slice(sql.as_bytes());
                self.buf.push(0);
            }
            // ... other messages
        }

        &self.buf
    }
}
```

### Message Reader
```rust
pub struct MessageReader {
    buf: Vec<u8>,
    pos: usize,
}

impl MessageReader {
    /// Read a backend message from bytes
    pub fn read(&mut self, data: &[u8]) -> Result<Option<BackendMessage>, Error> {
        if data.len() < 5 {
            return Ok(None);  // Need more data
        }

        let type_byte = data[0];
        let length = i32::from_be_bytes([data[1], data[2], data[3], data[4]]) as usize;

        if data.len() < length + 1 {
            return Ok(None);  // Need more data
        }

        let payload = &data[5..length + 1];

        let msg = match type_byte {
            b'R' => self.parse_authentication(payload)?,
            b'K' => self.parse_backend_key_data(payload)?,
            b'S' => self.parse_parameter_status(payload)?,
            b'Z' => self.parse_ready_for_query(payload)?,
            b'T' => self.parse_row_description(payload)?,
            b'D' => self.parse_data_row(payload)?,
            b'C' => self.parse_command_complete(payload)?,
            b'E' => self.parse_error_response(payload)?,
            b'N' => self.parse_notice_response(payload)?,
            b'1' => BackendMessage::ParseComplete,
            b'2' => BackendMessage::BindComplete,
            b'3' => BackendMessage::CloseComplete,
            // ... other types
            _ => return Err(Error::Protocol(format!("Unknown message type: {}", type_byte as char))),
        };

        Ok(Some(msg))
    }

    fn parse_authentication(&self, payload: &[u8]) -> Result<BackendMessage, Error> {
        let auth_type = i32::from_be_bytes([payload[0], payload[1], payload[2], payload[3]]);

        match auth_type {
            0 => Ok(BackendMessage::AuthenticationOk),
            3 => Ok(BackendMessage::AuthenticationCleartextPassword),
            5 => {
                let salt = [payload[4], payload[5], payload[6], payload[7]];
                Ok(BackendMessage::AuthenticationMD5Password(salt))
            }
            10 => {
                // SASL: parse mechanism list
                let mechanisms = self.parse_string_list(&payload[4..])?;
                Ok(BackendMessage::AuthenticationSASL(mechanisms))
            }
            11 => Ok(BackendMessage::AuthenticationSASLContinue(payload[4..].to_vec())),
            12 => Ok(BackendMessage::AuthenticationSASLFinal(payload[4..].to_vec())),
            _ => Err(Error::Protocol(format!("Unknown auth type: {}", auth_type))),
        }
    }

    // ... other parse methods
}
